import { Component, signal, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute } from '@angular/router';
import { SalesOrder, SOStatus } from '../../core/models';

@Component({
  selector: 'app-so-list',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './so-list.component.html',
})
export class SoListComponent {
  private route = inject(ActivatedRoute);

  orders = signal<SalesOrder[]>([
    {
      id: 'so1',
      reference: 'SO-2001',
      customerId: 'c1',
      customerName: 'Northwind Traders',
      status: 'confirmed',
      createdAt: '2026-07-09',
      total: 730,
      lines: [
        { id: 'sol1', productId: 'p1', productName: 'Steel Bolt M8', sku: 'STL-001', qty: 200, unitPrice: 1.20 },
        { id: 'sol2', productId: 'p8', productName: 'Proximity Sensor', sku: 'SEN-200', qty: 10, unitPrice: 49.00 },
      ],
    },
    {
      id: 'so2',
      reference: 'SO-2002',
      customerId: 'c2',
      customerName: 'Contoso Ltd',
      status: 'draft',
      createdAt: '2026-07-10',
      total: 150,
      lines: [
        { id: 'sol3', productId: 'p3', productName: 'PVC Pipe 50mm', sku: 'PIP-050', qty: 20, unitPrice: 7.50 },
      ],
    },
    {
      id: 'so3',
      reference: 'SO-2003',
      customerId: 'c3',
      customerName: 'Fabrikam Inc',
      status: 'fulfilled',
      createdAt: '2026-07-06',
      total: 880,
      lines: [
        { id: 'sol4', productId: 'p5', productName: 'Copper Wire 14AWG', sku: 'WIR-014', qty: 10, unitPrice: 24.00 },
        { id: 'sol5', productId: 'p7', productName: 'Control Panel', sku: 'PNL-100', qty: 2, unitPrice: 320.00 },
      ],
    },
    {
      id: 'so4',
      reference: 'SO-2000',
      customerId: 'c1',
      customerName: 'Northwind Traders',
      status: 'invoiced',
      createdAt: '2026-07-02',
      total: 735,
      lines: [
        { id: 'sol6', productId: 'p8', productName: 'Proximity Sensor', sku: 'SEN-200', qty: 15, unitPrice: 49.00 },
      ],
    },
  ]);

  status = signal<string>(this.route.snapshot.queryParamMap.get('status') ?? '');

  filtered = computed(() =>
    this.status()
      ? this.orders().filter((o) => o.status === this.status())
      : this.orders()
  );

  constructor() {
    this.route.queryParamMap.subscribe((params) => {
      this.status.set(params.get('status') ?? '');
    });
  }

  statusBadge(s: SOStatus): string {
    switch (s) {
      case 'draft':
        return 'badge badge-neutral';
      case 'confirmed':
        return 'badge badge-info';
      case 'fulfilled':
        return 'badge badge-warning';
      case 'invoiced':
        return 'badge badge-success';
    }
  }
}
